import { Component } from '@angular/core';
import { RouterLink, RouterLinkActive } from '@angular/router';

@Component({
  selector: 'app-header',
  standalone: true,
  imports: [RouterLink, RouterLinkActive],
  templateUrl: './header.component.html',
  styleUrls: ['./header.component.scss']
})
export class HeaderComponent {
  isMenuOpen = false;

  toggleMenu() {
    this.isMenuOpen = !this.isMenuOpen;
  }

  closeMenu() {
    this.isMenuOpen = false;
  }
}
<header class="site-header">
  <div class="container header-inner">
    <a routerLink="/" class="brand" (click)="closeMenu()">
      <div class="brand-mark">DGRAD</div>
      <div class="brand-text">
        <span class="brand-title">Direction Générale des Recettes Administratives, Judiciaires, Domaniales et de Participations</span>
        <span class="brand-subtitle">Ministère des Finances – République Démocratique du Congo</span>
      </div>
    </a>

    <button class="menu-toggle" type="button" (click)="toggleMenu()">
      <span class="menu-icon"></span>
    </button>

    <nav class="nav" [class.nav-open]="isMenuOpen">
      <a routerLink="/" routerLinkActive="active" [routerLinkActiveOptions]="{ exact: true }" (click)="closeMenu()">Accueil</a>
      <a routerLink="/a-propos" routerLinkActive="active" (click)="closeMenu()">Institution</a>
      <a routerLink="/missions-services" routerLinkActive="active" (click)="closeMenu()">Missions &amp; Services</a>
      <a routerLink="/documentation" routerLinkActive="active" (click)="closeMenu()">Documentation</a>
      <a routerLink="/galerie" routerLinkActive="active" (click)="closeMenu()">Galerie</a>
      <a routerLink="/contact" routerLinkActive="active" (click)="closeMenu()">Contact</a>
    </nav>
  </div>
</header>
